package com.treeeducation.ioas.audit; import io.swagger.v3.oas.annotations.media.Schema;import java.time.Instant; /** Audit DTOs. */ public final class AuditLogDtos{private AuditLogDtos(){} @Schema(description="审计日志响应") public record Response(Long id,AuditAction action,String targetType,Long targetId,Long actorId,String detail,Instant createdAt){} public static Response of(AuditLog l){return new Response(l.getId(),l.getAction(),l.getTargetType(),l.getTargetId(),l.getActorId(),l.getDetail(),l.getCreatedAt());}}
